import android.util.Log
import timber.log.Timber

class AppLogging {
    companion object {
        private const val TAG = "AppLogging"

        fun init() {
            if (BuildConfig.DEBUG) {
                Timber.plant(Timber.DebugTree())
            } else {
                Timber.plant(object : Timber.Tree() {
                    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                        when (priority) {
                            Log.VERBOSE -> Log.v(tag ?: TAG, message)
                            Log.DEBUG -> Log.d(tag ?: TAG, message)
                            Log.INFO -> Log.i(tag ?: TAG, message)
                            Log.WARN -> Log.w(tag ?: TAG, message)
                            Log.ERROR -> Log.e(tag ?: TAG, message)
                            else -> {
                                // Ignore unknown priority
                            }
                        }
                    }
                })
            }
        }

        fun logUserAuthentication(username: String, success: Boolean) {
            val status = if (success) "Successful" else "Failed"
            Timber.d("User authentication attempt for $username: $status")
        }

        fun logDatabaseQuery(query: String, params: Map<String, Any>) {
            Timber.v("Executing database query: $query with parameters: $params")
        }

        fun logApiRequest(url: String, headers: Map<String, String>, body: String?) {
            val headerString = headers.map { "${it.key}: ${it.value}" }.joinToString("\n")
            val requestBody = body?.let { "\nBody:\n$body" } ?: ""
            Timber.v("Making API request to $url\nHeaders:\n$headerString$requestBody")
        }

        fun logException(e: Throwable) {
            Timber.e(e, "An exception occurred")
        }
